// Script Continued Below
(function executeRule(current, previous /*null when async*/) {

	var taskingScripts = new tasking_System_Settings_Scripts();
	var UserPermissions = new UserInfoScripts();
	var IsTaskAdministrator =  (UserPermissions.IsUserTaskAdministrator() + '' == 'true');
	var IsTemplateAdmin =  (UserPermissions.userHasProcessTemplateAdminRights() + '' == 'true');

	var userHasPersonalProcessRights = (UserPermissions.userHasPersonalProcessRights() + '' == 'true');
	// if the user has personal template permissions, they can run personal templates
	g_scratchpad.userHasPersonalTemplateRights = (userHasPersonalProcessRights || IsTemplateAdmin);

	var isTaskManager = (taskingScripts.getMyOUTaskManagers(gs.getUserID()).length > 0);
	var isTemplateDesigner = (taskingScripts.getMyOUTemplateDesigners(gs.getUserID()).length > 0);
	// if the user has OU template permissions, they can run personal templates
	g_scratchpad.userHasOUTemplateRights = (isTaskManager || isTemplateDesigner || IsTaskAdministrator || IsTemplateAdmin);	


	var userHasGlobalProcessRights =  (UserPermissions.userHasGlobalProcessRights() + '' == 'true');
	// if user is a Task Administrator, TemplateAdmin, or global template designer they can run Global Templates
	g_scratchpad.userHasGlobalTemplateRights =  (userHasGlobalProcessRights || IsTaskAdministrator || IsTemplateAdmin);

})(current, previous);
